query:
-- Fix wa_conversations with lastFromMe=1 but lastStatus='pending' -> set to 'sent'
UPDATE wa_conversations SET lastStatus = 'sent' WHERE lastFromMe = 1 AND lastStatus IN ('pending', 'error');

-- Fix wa_conversations with lastFromMe=1 but lastStatus='received' (impossible for fromMe) -> set to 'sent'
UPDATE wa_conversations SET lastStatus = 'sent' WHERE lastFromMe = 1 AND lastStatus = 'received';

-- Fix wa_conversations with lastFromMe=1 but lastStatus='edited' -> set to 'delivered' (was read/delivered before edit)
UPDATE wa_conversations SET lastStatus = 'delivered' WHERE lastFromMe = 1 AND lastStatus = 'edited';

-- Verify
SELECT lastStatus, COUNT(*) as cnt FROM wa_conversations WHERE lastFromMe = 1 GROUP BY lastStatus;

